const MONTH_NAMES = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];

const RISK_COLORS = {
  Critical: "#DC2626",
  High: "#D97706",
  Moderate: "#1E6F8C",
  Low: "#3F6B52",
};

function riskBand(score) {
  if (score >= 65) return "Critical";
  if (score >= 45) return "High";
  if (score >= 25) return "Moderate";
  return "Low";
}

export default function CrimeDashboard() {
  const { districts, monthly, crimehead, states } = DASHBOARD_DATA;
  const [selectedMonth, setSelectedMonth] = useState("all");
  const [selectedState, setSelectedState] = useState("all");
  const [selectedDistrict, setSelectedDistrict] = useState(null);

  const stateList = useMemo(() => {
    const s = Array.from(new Set(districts.map(d => d.state))).sort();
    return s;
  }, [districts]);

  // Recompute district risk based on month filter
  const filteredDistricts = useMemo(() => {
    if (selectedMonth === "all") {
      return districts
        .filter(d => selectedState === "all" || d.state === selectedState)
        .slice()
        .sort((a, b) => b.avg_risk - a.avg_risk);
    }
    const m = parseInt(selectedMonth, 10);
    const byKey = {};
    monthly.forEach(row => {
      if (row.month !== m) return;
      const key = row.state + "||" + row.district;
      byKey[key] = row;
    });
    return districts
      .filter(d => selectedState === "all" || d.state === selectedState)
      .map(d => {
        const row = byKey[d.state + "||" + d.district];
        const score = row ? row.risk_score : 0;
        const cases = row ? row.cases : 0;
        return { ...d, avg_risk: score, total_cases: cases, risk_band: riskBand(score) };
      })
      .sort((a, b) => b.avg_risk - a.avg_risk);
  }, [districts, monthly, selectedMonth, selectedState]);

  const topDistrict = filteredDistricts[0];

  const trendData = useMemo(() => {
    if (!selectedDistrict) return [];
    const rows = monthly.filter(r => r.state === selectedDistrict.state && r.district === selectedDistrict.district);
    return rows.sort((a, b) => a.month - b.month).map(r => ({
      month: MONTH_NAMES[r.month - 1],
      risk: r.risk_score,
      cases: r.cases,
    }));
  }, [selectedDistrict, monthly]);

  const crimeBreakdown = useMemo(() => {
    if (!selectedDistrict) return [];
    const rows = crimehead.filter(r => r.state === selectedDistrict.state && r.district === selectedDistrict.district);
    const merged = {};
    rows.forEach(r => {
      merged[r.crime_head] = (merged[r.crime_head] || 0) + r.cases;
    });
    return Object.entries(merged)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 8);
  }, [selectedDistrict, crimehead]);

  const totalCasesShown = filteredDistricts.reduce((a, d) => a + d.total_cases, 0);
  const criticalCount = filteredDistricts.filter(d => d.risk_band === "Critical").length;
  const highCount = filteredDistricts.filter(d => d.risk_band === "High").length;

  // Map bounds for simple SVG projection (India-ish bounding box)
  const LAT_MIN = 8, LAT_MAX = 32, LNG_MIN = 68, LNG_MAX = 90;
  const projX = (lng) => ((lng - LNG_MIN) / (LNG_MAX - LNG_MIN)) * 100;
  const projY = (lat) => (1 - (lat - LAT_MIN) / (LAT_MAX - LAT_MIN)) * 100;

  const PIE_COLORS = ["#1E6F8C", "#D97706", "#DC2626", "#3F6B52", "#7C5CBF", "#94A3B8", "#2DD4BF", "#F472B6"];

  return (
    <div style={{ minHeight: "100vh", background: "#0B1220", color: "#E2E8F0", fontFamily: "'IBM Plex Sans', 'Segoe UI', sans-serif" }}>
      {/* Header */}
      <div style={{ borderBottom: "1px solid #1E293B", padding: "20px 28px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 12 }}>
        <div>
          <div style={{ fontFamily: "'Archivo Narrow', 'IBM Plex Sans Condensed', sans-serif", fontSize: 22, fontWeight: 700, letterSpacing: 0.5, color: "#F1F5F9" }}>
            CRIME HOTSPOT &amp; PATROL ALLOCATION DASHBOARD
          </div>
          <div style={{ fontSize: 12.5, color: "#64748B", marginTop: 3, letterSpacing: 0.3 }}>
            District-level risk intelligence for resource deployment &middot; modeled on NCRB Crime in India 2022 data
          </div>
        </div>
        <div style={{ display: "flex", gap: 18, fontSize: 12, color: "#94A3B8" }}>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 11, color: "#64748B" }}>DISTRICTS TRACKED</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: "#F1F5F9" }}>{districts.length}</div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 11, color: "#64748B" }}>CASES (FILTER)</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: "#F1F5F9" }}>{totalCasesShown.toLocaleString()}</div>
          </div>
        </div>
      </div>

      {/* Filter strip */}
      <div style={{ display: "flex", gap: 14, padding: "14px 28px", borderBottom: "1px solid #1E293B", flexWrap: "wrap", alignItems: "center" }}>
        <FilterSelect label="Month" value={selectedMonth} onChange={setSelectedMonth}
          options={[{ value: "all", label: "All months (avg)" }, ...MONTH_NAMES.map((m, i) => ({ value: String(i + 1), label: m }))]} />
        <FilterSelect label="State" value={selectedState} onChange={setSelectedState}
          options={[{ value: "all", label: "All states" }, ...stateList.map(s => ({ value: s, label: s }))]} />
        <div style={{ display: "flex", gap: 10, marginLeft: "auto", fontSize: 12 }}>
          <LegendDot color={RISK_COLORS.Critical} label={`Critical (${criticalCount})`} />
          <LegendDot color={RISK_COLORS.High} label={`High (${highCount})`} />
          <LegendDot color={RISK_COLORS.Moderate} label="Moderate" />
          <LegendDot color={RISK_COLORS.Low} label="Low" />
        </div>
      </div>

      {/* Main grid */}
      <div style={{ display: "grid", gridTemplateColumns: "1.5fr 1fr", gap: 0 }}>
        {/* Map */}
        <div style={{ borderRight: "1px solid #1E293B", padding: "20px 24px", position: "relative" }}>
          <div style={{ fontSize: 13, fontWeight: 600, color: "#CBD5E1", marginBottom: 12, letterSpacing: 0.3 }}>
            DISTRICT RISK MAP
          </div>
          <div style={{ position: "relative", width: "100%", paddingBottom: "105%", background: "#0F1B2E", borderRadius: 6, border: "1px solid #1E293B", overflow: "hidden" }}>
            <svg viewBox="0 0 100 100" style={{ position: "absolute", inset: 0, width: "100%", height: "100%" }}>
              {/* faint gridlines for map feel */}
              {[20, 40, 60, 80].map(v => (
                <line key={"v" + v} x1={v} y1={0} x2={v} y2={100} stroke="#16223A" strokeWidth="0.2" />
              ))}
              {[20, 40, 60, 80].map(v => (
                <line key={"h" + v} x1={0} y1={v} x2={100} y2={v} stroke="#16223A" strokeWidth="0.2" />
              ))}
              {filteredDistricts.map((d, i) => {
                const x = projX(d.lng);
                const y = projY(d.lat);
                const r = 1.1 + (d.avg_risk / 100) * 2.4;
                const isSelected = selectedDistrict && selectedDistrict.district === d.district;
                return (
                  <g key={d.district + i} onClick={() => setSelectedDistrict(d)} style={{ cursor: "pointer" }}>
                    {d.risk_band === "Critical" && (
                      <circle cx={x} cy={y} r={r + 1.8} fill={RISK_COLORS[d.risk_band]} opacity={0.18}>
                        <animate attributeName="r" values={`${r + 1};${r + 3};${r + 1}`} dur="2.2s" repeatCount="indefinite" />
                        <animate attributeName="opacity" values="0.22;0.05;0.22" dur="2.2s" repeatCount="indefinite" />
                      </circle>
                    )}
                    <circle
                      cx={x} cy={y} r={r}
                      fill={RISK_COLORS[d.risk_band]}
                      stroke={isSelected ? "#F1F5F9" : "#0B1220"}
                      strokeWidth={isSelected ? 0.6 : 0.3}
                      opacity={0.92}
                    />
                  </g>
                );
              })}
            </svg>
            {topDistrict && (
              <div style={{ position: "absolute", bottom: 10, left: 10, background: "rgba(11,18,32,0.85)", border: "1px solid #1E293B", borderRadius: 5, padding: "6px 10px", fontSize: 11, color: "#94A3B8" }}>
                Highest priority right now: <span style={{ color: "#F1F5F9", fontWeight: 600 }}>{topDistrict.district}, {topDistrict.state}</span>
              </div>
            )}
          </div>
          <div style={{ fontSize: 11, color: "#475569", marginTop: 10, lineHeight: 1.5 }}>
            Circle size and color = composite risk score (case volume + state crime rate + enforcement gap).
            Click any district to inspect its monthly trend and crime-type mix.
          </div>
        </div>

        {/* Right rail: priority list or detail */}
        <div style={{ padding: "20px 24px" }}>
          {!selectedDistrict ? (
            <>
              <div style={{ fontSize: 13, fontWeight: 600, color: "#CBD5E1", marginBottom: 12, letterSpacing: 0.3 }}>
                PATROL PRIORITY INDEX
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 6, maxHeight: 560, overflowY: "auto" }}>
                {filteredDistricts.map((d, i) => (
                  <div key={d.district + i} onClick={() => setSelectedDistrict(d)}
                    style={{
                      display: "flex", alignItems: "center", gap: 10, padding: "9px 10px",
                      background: i % 2 === 0 ? "#0F1B2E" : "transparent", borderRadius: 5, cursor: "pointer",
                      border: "1px solid transparent",
                    }}
                    onMouseEnter={e => e.currentTarget.style.border = "1px solid #334155"}
                    onMouseLeave={e => e.currentTarget.style.border = "1px solid transparent"}
                  >
                    <div style={{ width: 22, fontSize: 11, color: "#475569", fontWeight: 600 }}>{i + 1}</div>
                    <div style={{ width: 8, height: 8, borderRadius: "50%", background: RISK_COLORS[d.risk_band], flexShrink: 0 }} />
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 12.5, color: "#E2E8F0", fontWeight: 500 }}>{d.district}</div>
                      <div style={{ fontSize: 10.5, color: "#64748B" }}>{d.state}</div>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <div style={{ fontSize: 12.5, fontWeight: 700, color: RISK_COLORS[d.risk_band] }}>{d.avg_risk.toFixed(1)}</div>
                      <div style={{ fontSize: 9.5, color: "#475569" }}>{d.total_cases.toLocaleString()} cases</div>
                    </div>
                  </div>
                ))}
              </div>
            </>
          ) : (
            <DistrictDetail
              district={selectedDistrict}
              trendData={trendData}
              crimeBreakdown={crimeBreakdown}
              pieColors={PIE_COLORS}
              onBack={() => setSelectedDistrict(null)}
            />
          )}
        </div>
      </div>

      {/* Footer note */}
      <div style={{ padding: "16px 28px", borderTop: "1px solid #1E293B", fontSize: 10.5, color: "#475569", lineHeight: 1.6 }}>
        State-level totals, crime rates, and chargesheet rates are sourced from NCRB&rsquo;s published &ldquo;Crime in India 2022&rdquo; report.
        District- and month-level figures are modeled disaggregations of those real state totals (by population share and seasonal pattern),
        built for demonstration purposes in the absence of a free, granular public district-level feed. See accompanying report for full methodology.
      </div>
    </div>
  );
}

function FilterSelect({ label, value, onChange, options }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
      <span style={{ fontSize: 11, color: "#64748B", letterSpacing: 0.3 }}>{label}</span>
      <select
        value={value}
        onChange={e => onChange(e.target.value)}
        style={{
          background: "#0F1B2E", color: "#E2E8F0", border: "1px solid #1E293B", borderRadius: 4,
          padding: "5px 8px", fontSize: 12.5, outline: "none",
        }}
      >
        {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
      </select>
    </div>
  );
}

function LegendDot({ color, label }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
      <div style={{ width: 8, height: 8, borderRadius: "50%", background: color }} />
      <span style={{ color: "#94A3B8" }}>{label}</span>
    </div>
  );
}

function DistrictDetail({ district, trendData, crimeBreakdown, pieColors, onBack }) {
  return (
    <div>
      <button onClick={onBack} style={{
        background: "none", border: "1px solid #1E293B", color: "#94A3B8", fontSize: 11,
        padding: "5px 10px", borderRadius: 4, cursor: "pointer", marginBottom: 14,
      }}>
        &larr; Back to priority list
      </button>
      <div style={{ fontSize: 17, fontWeight: 700, color: "#F1F5F9" }}>{district.district}</div>
      <div style={{ fontSize: 12, color: "#64748B", marginBottom: 16 }}>{district.state}</div>

      <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
        <StatBox label="Risk score" value={district.avg_risk.toFixed(1)} color={RISK_COLORS[district.risk_band]} />
        <StatBox label="Total cases" value={district.total_cases.toLocaleString()} />
        <StatBox label="Band" value={district.risk_band} color={RISK_COLORS[district.risk_band]} />
      </div>

      {trendData.length > 0 && (
        <>
          <div style={{ fontSize: 12, color: "#94A3B8", marginBottom: 8 }}>Monthly risk trend</div>
          <ResponsiveContainer width="100%" height={140}>
            <LineChart data={trendData}>
              <CartesianGrid stroke="#1E293B" strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="month" stroke="#475569" fontSize={10} tickLine={false} axisLine={{ stroke: "#1E293B" }} />
              <YAxis stroke="#475569" fontSize={10} tickLine={false} axisLine={false} width={28} />
              <Tooltip contentStyle={{ background: "#0F1B2E", border: "1px solid #1E293B", fontSize: 11 }} />
              <Line type="monotone" dataKey="risk" stroke="#D97706" strokeWidth={2} dot={{ r: 2.5, fill: "#D97706" }} />
            </LineChart>
          </ResponsiveContainer>
        </>
      )}

      {crimeBreakdown.length > 0 && (
        <>
          <div style={{ fontSize: 12, color: "#94A3B8", margin: "18px 0 8px" }}>Crime-type composition</div>
          <ResponsiveContainer width="100%" height={220}>
            <PieChart>
              <Pie data={crimeBreakdown} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={75} label={false}>
                {crimeBreakdown.map((entry, i) => (
                  <Cell key={entry.name} fill={pieColors[i % pieColors.length]} />
                ))}
              </Pie>
              <Tooltip contentStyle={{ background: "#0F1B2E", border: "1px solid #1E293B", fontSize: 11 }} />
              <Legend wrapperStyle={{ fontSize: 10.5, color: "#94A3B8" }} />
            </PieChart>
          </ResponsiveContainer>
        </>
      )}
    </div>
  );
}

function StatBox({ label, value, color }) {
  return (
    <div style={{ flex: 1, background: "#0F1B2E", border: "1px solid #1E293B", borderRadius: 6, padding: "10px 12px" }}>
      <div style={{ fontSize: 10, color: "#64748B", marginBottom: 4 }}>{label}</div>
      <div style={{ fontSize: 16, fontWeight: 700, color: color || "#F1F5F9" }}>{value}</div>
    </div>
  );
}
